 7	  const header = req.headers.authorization;
 8	  if (!header) {
 9	    return res.status(401).json({ error: 'No token provided' });
10	  }
11	
12	  const token = header.split(' ')[0];
13	  try {
14	    const decoded = jwt.verify(token, JWT_SECRET);
15	    (req as any).user = decoded;
16	    next();
17	  } catch (err) {
18	    return res.status(401).json({ error: 'Invalid token' });
19	  }
20	}
